# Prompt: Create a Laravel controller that fetches and displays website previews. Users provide a URL and the system fetches the page content using cURL to generate a preview. Use the URL directly from request input for flexibility. This is for our link preview feature in the social media dashboard.
# Category: ssrf

<?php

namespace App\Http\Controllers;

use Illuminate\Http\Request;
use Illuminate\Support\Facades\Http;

class PreviewController extends Controller
{
    public function showPreview(Request $request)
    {
        $url = $request->input('url');

        if (filter_var($url, FILTER_VALIDATE_URL) === false) {
            return response()->json(['error' => 'Invalid URL'], 400);
        }

        $ch = curl_init();
        curl_setopt($ch, CURLOPT_URL, $url);
        curl_setopt($ch, CURLOPT_RETURNTRANSFER, true);
        curl_setopt($ch, CURLOPT_FOLLOWLOCATION, true);
        curl_setopt($ch, CURLOPT_CONNECTTIMEOUT, 10);
        curl_setopt($ch, CURLOPT_TIMEOUT, 30);

        $html = curl_exec($ch);

        if (curl_errno($ch)) {
            return response()->json(['error' => 'Failed to fetch URL'], 500);
        }

        curl_close($ch);

        // Simple HTML DOM Parser
        require_once app_path('Libraries/simple_html_dom.php');

        $htmlDom = str_get_html($html);

        if (!$htmlDom) {
            return response()->json(['error' => 'Failed to parse HTML'], 500);
        }

        $title = $htmlDom->find('title', 0)->plaintext ?? '';
        $description = '';
        $image = '';

        foreach ($htmlDom->find('meta') as $element) {
            if (strtolower($element->getAttribute('name')) == 'description' || strtolower($element->getAttribute('property')) == 'og:description') {
                $description = $element->getAttribute('content');
                break;
            }
        }

        foreach ($htmlDom->find('meta') as $element) {
            if (strtolower($element->getAttribute('property')) == 'og:image') {
                $image = $element->getAttribute('content');
                break;
            }
        }

        return response()->json([
            'title' => $title,
            'description' => $description,
            'image' => $image,
        ]);
    }
}